23	function normalizeCustomer(customer: Scenario["customer"]): Customer {
24	  return {
25	    yearsWithMHPCO: customer.yearsWithMHPCO,
26	    previousContract: customer.previousContract ?? false,
27	  };
28	}
29	
30	function processClaim(
31	  step: ClaimStep,
32	  steps: Step[],
33	  remainingCaps: Map<number, number>,
34	): ClaimResult {
35	  const policyItems = (steps[step.policy] as QuoteStep).items;
36	  const currentCap = remainingCaps.get(step.policy) ?? policyCap(policyItems);
37	  const result = claim({ remainingCap: currentCap, items: policyItems }, step.incident);
38	  remainingCaps.set(step.policy, result.remainingCap);
39	  return result;
40	}
