43	  const customer = normalizeCustomer(scenario.customer);
44	  const results: StepResult[] = [];
45	  const steps = scenario.steps;
46	  const remainingCaps = new Map<number, number>();
47	  let quotesSoFar = 0;
48	  for (const step of steps) {
49	    if (step.op === "quote") {
50	      const quoteCustomer = { ...customer, previousContract: quotesSoFar > 0 };
